158	  /**
159	   * Дозаполнить банк под покрытие: для каждого KC с дефицитом активных вопросов
160	   * генерируем недостающие, верифицируем (LLM-judge), дедуплицируем и сохраняем.
161	   * Если подтверждённых KC нет — генерируем на уровне узла (без KC-тега).
162	   */
163	  async generateForCoverage(
164	    subjectId: string,
165	    ktpTopicId: string,
166	    opts?: { minPerKc?: number; difficulty?: number }
167	  ): Promise<{ created: number; rejected: number; coverage: Awaited<ReturnType<QuestionBankService['coverage']>> }> {
168	    await this.assertSubject(subjectId);
169	    const minPerKc = Math.max(1, opts?.minPerKc ?? DEFAULT_MIN_ITEMS_PER_KC);
170	    const centerDifficulty = Math.min(5, Math.max(1, opts?.difficulty ?? 3));
171	
172	    const resolved = await this.resolveNode(subjectId, ktpTopicId);
173	    if (!resolved.sourceText.trim()) throw AppError.badRequest('Node has no source text to ground questions');
174	
175	    const kcs = await knowledgeComponentService.getConfirmed(subjectId, ktpTopicId);
176	
177	    let created = 0;
178	    let rejected = 0;
179	    const rejectReasons: string[] = [];
180	    const MAX_ROUNDS = 3; // верификатор режет часть — добираем в несколько проходов
181	
182	    for (let round = 0; round < MAX_ROUNDS; round++) {
183	      const cov = await this.coverage(subjectId, ktpTopicId);
184	      // Цели: KC с дефицитом активных, либо одна цель на узел (если KC нет).
185	      const targets: Array<{ kcId?: string; title: string; deficit: number }> = kcs.length
186	        ? cov.perKc
187	            .filter((p) => p.active < minPerKc)
188	            .map((p) => ({ kcId: p.kcId, title: p.title, deficit: minPerKc - p.active }))
189	        : cov.totalActive < minPerKc
190	          ? [{ title: resolved.nodeTitle, deficit: minPerKc - cov.totalActive }]
191	          : [];
192	      if (targets.length === 0) break;
193	
194	      let producedThisRound = 0;
195	      for (const target of targets) {
196	        for (const bucket of buildDifficultyPlan(target.deficit, centerDifficulty)) {
197	          let generated: IQuestion[];
198	          try {
199	            generated = await aiService.generateKcQuestions({
200	              nodeTitle: resolved.nodeTitle,
201	              kcTitle: target.title,
202	              sourceText: resolved.sourceText,
203	              ...(resolved.language ? { language: resolved.language } : {}),
204	              count: bucket.count,
205	              difficulty: bucket.difficulty
206	            });
207	          } catch (e) {
208	            console.warn('[questionBank] generation failed for', target.title, e);
209	            continue;
210	          }
211	
212	          for (const q of generated) {
213	            // Верификация (анти-галлюцинации).
214	            const verdict = await aiService.verifyQuestionItem({ question: q, sourceText: resolved.sourceText });
215	            if (!verdict.ok) {
216	              rejected++;
217	              if (verdict.reason) rejectReasons.push(verdict.reason);
218	              continue;
219	            }
220	            const doc: Omit<IQuestionItem, '_id' | 'createdAt' | 'updatedAt'> = {
221	              subjectId: new mongoose.Types.ObjectId(subjectId),
222	              knowledgeNodeId: ktpTopicId,
223	              knowledgeComponentIds: target.kcId ? [target.kcId] : [],
224	              question: q,
225	              difficulty: bucket.difficulty,
226	              status: 'active',
227	              sourceRefs: resolved.sourceRefs.map((r) => ({
228	                ...(r.bookId ? { bookId: new mongoose.Types.ObjectId(r.bookId) } : {}),
229	                ...(r.chapterId ? { chapterId: new mongoose.Types.ObjectId(r.chapterId) } : {}),
230	                ...(r.topicId ? { topicId: new mongoose.Types.ObjectId(r.topicId) } : {})
231	              })),
232	              provenance: {
233	                model: 'gpt-4o-mini',
234	                promptVersion: BANK_PROMPT_VERSION,
235	                generatedAt: new Date(),
236	                verified: true,
237	                ...(verdict.reason ? { verifyReason: verdict.reason } : {})
238	              },
239	              contentHash: contentHashOf(q),
240	              qualityStats: { timesUsed: 0, timesCorrect: 0 }
241	            };
242	            try {
243	              await QuestionItem.create(doc);
244	              created++;
245	              producedThisRound++;
246	            } catch (e: unknown) {
247	              // Дубликат (уникальный индекс по contentHash в узле) — молча пропускаем.
248	              if ((e as { code?: number }).code === 11000) continue;
249	              console.warn('[questionBank] insert failed', e);
250	            }
251	          }
252	        }
253	      }
254	      if (producedThisRound === 0) break; // прогресса нет — не крутим вхолостую
255	    }
256	
257	    if (rejectReasons.length) {
258	      console.warn(`[questionBank] отклонено верификатором: ${rejected}. Примеры причин:`);
259	      for (const r of rejectReasons.slice(0, 8)) console.warn('   •', r);
260	    }
261	
262	    const coverageAfter = await this.coverage(subjectId, ktpTopicId);
263	    return { created, rejected, coverage: coverageAfter };
264	  }
