270	  async assembleNodeTest(
271	    subjectId: string,
272	    ktpTopicId: string,
273	    opts?: { userId?: string; size?: number }
274	  ): Promise<InstanceType<typeof Test>> {
275	    await this.assertSubject(subjectId);
276	    const size = normalizeTestSize(opts?.size);
