278	    // Адаптивный контекст: пер-KC mastery (слабые темы вперёд) + недавние item'ы (SR).
279	    const ctx = opts?.userId
280	      ? {
281	          componentMap: await userKcMasteryService.getComponentMap(opts.userId, subjectId),
282	          recentItems: await userKcMasteryService.getRecentItemIds(opts.userId, subjectId)
283	        }
284	      : undefined;
285	
286	    let items = await this.selectCovering(subjectId, ktpTopicId, size, ctx);
287	    if (items.length < size) {
288	      // дозаполняем банк под нужный размер (минимум на KC масштабируем от size) и пробуем ещё раз
289	      const cov = await this.coverage(subjectId, ktpTopicId);
290	      const kcCount = Math.max(1, cov.perKc.length);
291	      const minPerKc = Math.max(DEFAULT_MIN_ITEMS_PER_KC, Math.ceil(size / kcCount));
292	      await this.generateForCoverage(subjectId, ktpTopicId, { minPerKc });
293	      items = await this.selectCovering(subjectId, ktpTopicId, size, ctx);
294	    }
295	    if (items.length < size) {
296	      throw AppError.badRequest(
297	        `Недостаточно вопросов в банке для сборки теста (есть ${items.length} из ${size}). Сгенерируйте больше.`
298	      );
299	    }
