301	    const resolved = await this.resolveNode(subjectId, ktpTopicId);
302	    if (!resolved.primary.bookId) throw AppError.badRequest('Node has no primary book to attach test');
303	
304	    const selected = items.slice(0, size);
305	    const sourceContentHash =
306	      `bank:${size}:` +
307	      createHash('sha256')
308	        .update(`${size}|` + selected.map((i) => String(i._id)).sort().join(','))
309	        .digest('hex');
310	
311	    // Реюз: та же выборка → тот же тест.
312	    const existing = await Test.findOne({ subjectId, sourceContentHash }).sort({ createdAt: -1 });
313	    if (existing) return existing;
314	
315	    const questions: IQuestion[] = selected.map((it) => {
316	      const q = it.question as IQuestion;
317	      return {
318	        ...q,
319	        relatedContent: {
320	          ...q.relatedContent,
321	          ...(resolved.primary.chapterId
322	            ? { chapterId: new mongoose.Types.ObjectId(resolved.primary.chapterId) }
323	            : {})
324	        },
325	        questionItemId: it._id as mongoose.Types.ObjectId,
326	        ...(it.knowledgeComponentIds?.length ? { knowledgeComponentIds: it.knowledgeComponentIds } : {})
327	      };
328	    });
329	
330	    await QuestionItem.updateMany(
331	      { _id: { $in: selected.map((i) => i._id) } },
332	      { $inc: { 'qualityStats.timesUsed': 1 } }
333	    );
334	
335	    return Test.create({
336	      subjectId,
337	      bookId: resolved.primary.bookId,
338	      ...(resolved.primary.chapterId ? { chapterId: resolved.primary.chapterId } : {}),
339	      questions,
340	      sourceContentHash,
