345	  /**
346	   * Выбрать активные item'ы, максимизируя покрытие KC (round-robin по KC), до `size`.
347	   * Если задан ctx (пер-KC mastery + недавние item'ы): слабые/неосвоенные KC идут первыми,
348	   * внутри KC — деприоритет недавно показанных (SR) и подбор сложности под уровень освоения.
349	   */
350	  private async selectCovering(
351	    subjectId: string,
352	    ktpTopicId: string,
353	    size: number,
354	    ctx?: { componentMap: Map<string, IUserKcComponentProgress>; recentItems: Set<string> }
355	  ) {
356	    const active = await QuestionItem.find({ subjectId, knowledgeNodeId: ktpTopicId, status: 'active' })
357	      .sort({ 'qualityStats.timesUsed': 1, createdAt: 1 })
358	      .lean();
359	    if (active.length === 0) return [];
360	
361	    // Группируем по KC (item без KC → ключ '_node').
362	    const byKc = new Map<string, typeof active>();
363	    for (const it of active) {
364	      const keys = (it.knowledgeComponentIds ?? []) as string[];
365	      const groupKeys = keys.length ? keys : ['_node'];
366	      for (const k of groupKeys) {
367	        if (!byKc.has(k)) byKc.set(k, []);
368	        byKc.get(k)!.push(it);
369	      }
370	    }
371	
372	    const masteryOf = (kcId: string): number => ctx?.componentMap.get(kcId)?.bestScore ?? 0;
373	    const isRecent = (id: string): boolean => ctx?.recentItems.has(id) ?? false;
374	
375	    // Порядок KC: слабые/неосвоенные первыми (по возрастанию bestScore).
376	    const kcKeys = [...byKc.keys()];
377	    if (ctx) kcKeys.sort((a, b) => masteryOf(a) - masteryOf(b));
378	
379	    // Внутри KC: не показанные недавно — первыми; сложность под уровень (слабому — проще).
380	    for (const k of kcKeys) {
381	      const weak = ctx ? masteryOf(k) < 80 : false;
382	      byKc.get(k)!.sort((x, y) => {
383	        if (ctx) {
384	          const rx = isRecent(String(x._id)) ? 1 : 0;
385	          const ry = isRecent(String(y._id)) ? 1 : 0;
386	          if (rx !== ry) return rx - ry; // не-недавние вперёд
387	          const dx = x.difficulty ?? 3;
388	          const dy = y.difficulty ?? 3;
389	          if (dx !== dy) return weak ? dx - dy : dy - dx; // слабому проще, сильному сложнее
390	        }
391	        return (x.qualityStats?.timesUsed ?? 0) - (y.qualityStats?.timesUsed ?? 0);
392	      });
393	    }
394	
395	    const picked: typeof active = [];
396	    const usedIds = new Set<string>();
397	    let progress = true;
398	    while (picked.length < size && progress) {
399	      progress = false;
400	      for (const k of kcKeys) {
401	        if (picked.length >= size) break;
402	        const pool = byKc.get(k)!;
403	        const next = pool.find((it) => !usedIds.has(String(it._id)));
404	        if (next) {
405	          usedIds.add(String(next._id));
406	          picked.push(next);
407	          progress = true;
408	        }
409	      }
410	    }
411	    return picked;
412	  }
413	}
