32	/** Найти первый предмет + ktpTopicId, у которого узел КТП имеет источники. */
33	async function autoPick(): Promise<{ subjectId: string; ktpTopicId: string } | null> {
34	  const subjects = await Subject.find().lean();
35	  for (const subject of subjects) {
36	    const ktp = await KtpCatalog.findOne({ subjectId: subject._id }).lean<IKtpCatalog>();
37	    if (!ktp?.topics?.length) continue;
38	    const nodes = buildKtpCanonicalNodes(subject, ktp);
39	    const node = nodes.find(
40	      (n) => ((n.metadata as Record<string, unknown>)?.sources as unknown[] | undefined)?.length
41	    );
42	    const ktpTopicId = node && (node.metadata as Record<string, unknown>)?.ktpTopicId;
43	    if (typeof ktpTopicId === 'string') {
44	      return { subjectId: String(subject._id), ktpTopicId };
45	    }
46	  }
47	  return null;
48	}
